query:
-- Deletar itens dos pedidos primeiro (FK constraint)
DELETE FROM order_items;
-- Deletar todos os pedidos
DELETE FROM orders;
-- Deletar sessões de pedido expiradas/antigas
DELETE FROM order_sessions WHERE status IN ('completed', 'cancelled', 'expired');
-- Deletar categorias Pizzas e seus itens
DELETE FROM menu_items WHERE categoryId IN (SELECT id FROM menu_categories WHERE name LIKE '%Pizza%' OR name LIKE '%pizza%');
DELETE FROM menu_categories WHERE name LIKE '%Pizza%' OR name LIKE '%pizza%';

